1	/*!
2	 *  Copyright (c) 2023-2025 by Contributors
3	 * \file serve/engine_actions/batch_draft.cc
4	 */
5	
6	#include <numeric>
7	
8	#include "../config.h"
9	#include "../model.h"
10	#include "../sampler/sampler.h"
11	#include "action.h"
12	#include "action_commons.h"
13	
14	namespace mlc {
15	namespace llm {
16	namespace serve {
17	
18	/*!
19	 * \brief The action that runs draft proposal for requests in the
20	 * `running_queue` of engine state. Preempt low-priority requests
21	 * accordingly when it is impossible to decode all the running requests.
22	 */
23	class BatchDraftActionObj : public EngineActionObj {
24	 public:
25	  explicit BatchDraftActionObj(Array<Model> models, LogitProcessor logit_processor, Sampler sampler,
26	                               std::vector<ModelWorkspace> model_workspaces,
27	                               DraftTokenWorkspaceManager draft_token_workspace_manager,
28	                               EngineConfig engine_config,
29	                               Optional<EventTraceRecorder> trace_recorder)
30	      : models_(std::move(models)),
31	        logit_processor_(std::move(logit_processor)),
32	        sampler_(std::move(sampler)),
33	        model_workspaces_(std::move(model_workspaces)),
34	        draft_token_workspace_manager_(std::move(draft_token_workspace_manager)),
35	        engine_config_(std::move(engine_config)),
36	        trace_recorder_(std::move(trace_recorder)) {}
37	
38	  Array<Request> Step(EngineState estate) final {
39	    // - Only run spec decode when there are two models (llm+ssm) and >=1 running requests.
40	    if (models_.size() != 2 || estate->running_queue.empty()) {
41	      return {};
42	    }
43	
44	    // Preempt request state entries when decode cannot apply.
45	    std::vector<RequestStateEntry> running_rsentries = estate->GetRunningRequestStateEntries();
46	    while (!CanDecode(running_rsentries.size())) {
47	      if (estate->prefix_cache->TryFreeMemory()) continue;
48	      RequestStateEntry preempted = PreemptLastRunningRequestStateEntry(
49	          estate, models_, draft_token_workspace_manager_, trace_recorder_);
50	      if (preempted.same_as(running_rsentries.back())) {
51	        running_rsentries.pop_back();
52	      }
53	    }
54	    while (running_rsentries.size() * (engine_config_->spec_draft_length + 1) >
55	           std::min(static_cast<int64_t>(engine_config_->max_num_sequence),
56	                    engine_config_->prefill_chunk_size)) {
57	      running_rsentries.pop_back();
58	    }
59	
60	    auto tstart = std::chrono::high_resolution_clock::now();
61	
62	    int num_rsentries = running_rsentries.size();
63	    TVM_FFI_ICHECK_GT(num_rsentries, 0)
64	        << "There should be at least one request state entry that can run decode. "
65	           "Possible failure reason: none of the prefill phase of the running requests is finished";
66	    TVM_FFI_ICHECK_LE(num_rsentries, engine_config_->max_num_sequence)
67	        << "The number of running requests exceeds the max number of sequence in EngineConfig. "
68	           "Possible failure reason: the prefill action allows new sequence in regardless of the "
69	           "max num sequence.";
70	    Array<String> request_ids;
71	    std::vector<int64_t> request_internal_ids;
72	    Array<String> request_ids_per_leaf_node;
73	    Array<GenerationConfig> generation_cfg;
74	    Array<GenerationConfig> generation_cfg_for_logitproc;
75	    std::vector<RandomGenerator*> rngs;
76	    std::vector<std::vector<int>> draft_token_indices;
77	    // Number of input tokens for each request. Each request can have multiple leaf tokens for the
78	    // next forward when multiple tokens are drafted.
79	    std::vector<int> cum_num_tokens;
80	    std::vector<int64_t> token_tree_parent_ptr;
81	    request_ids.reserve(num_rsentries);
82	    request_internal_ids.reserve(num_rsentries);
83	    generation_cfg.reserve(num_rsentries);
84	    generation_cfg_for_logitproc.reserve(num_rsentries);
85	    draft_token_indices.reserve(num_rsentries);
86	    cum_num_tokens.reserve(num_rsentries + 1);
87	    for (const RequestStateEntry& rsentry : running_rsentries) {
88	      request_ids.push_back(rsentry->request->id);
89	      request_internal_ids.push_back(rsentry->mstates[0]->internal_id);
90	    }
91	
92	    TVM_FFI_ICHECK_GT(estate->spec_draft_length, 0)
93	        << "The speculative decoding draft length must be positive.";
94	    // The first model doesn't get involved in draft proposal.
95	    for (int model_id = 1; model_id < static_cast<int>(models_.size()); ++model_id) {
96	      // Collect
97	      // - the last committed token,
98	      // - the request model state of each request,
99	      // - the number of tokens for each request to send into the model (it may
100	      // be more than one if the draft model is lagging behind the main model, when
101	      // the engine switches from normal batch decode mode to speculative decoding mode).
102	      std::vector<int> input_tokens;
103	      Array<RequestModelState> mstates;
104	      std::vector<int> input_lengths;
105	      input_tokens.reserve(num_rsentries);
106	      mstates.reserve(num_rsentries);
107	      input_lengths.reserve(num_rsentries);
108	      for (const RequestStateEntry& rsentry : running_rsentries) {
109	        mstates.push_back(rsentry->mstates[model_id]);
110	      }
111	      // "Draft length" rounds of draft proposal.
112	      for (int draft_id = 0; draft_id < estate->spec_draft_length; ++draft_id) {
113	        auto tdraft_start = std::chrono::high_resolution_clock::now();
114	        // prepare new input tokens
115	        input_tokens.clear();
116	        input_lengths.clear();
117	        token_tree_parent_ptr.clear();
118	        generation_cfg.clear();
119	        generation_cfg_for_logitproc.clear();
120	        rngs.clear();
121	        cum_num_tokens.clear();
122	        cum_num_tokens.push_back(0);
123	        request_ids_per_leaf_node.clear();
124	        std::vector<int> draft_token_parent_idx;
125	        draft_token_indices.clear();
126	
127	        if (draft_id == 0) {
128	          // Compute the total length that needs to be processed by the draft model,
129	          // including the lagging-behind part of hte draft model.
130	          // When the total length to be processed is larger than the prefill chunk
131	          // size, we must do the prefill with multiple rounds by chunk.
132	          int total_length = 0;
133	          for (int i = 0; i < num_rsentries; ++i) {
134	            TVM_FFI_ICHECK_LE(mstates[i]->committed_tokens.size(),
135	                              running_rsentries[i]->mstates[0]->committed_tokens.size());
136	            total_length += running_rsentries[i]->mstates[0]->committed_tokens.size() -
137	                            mstates[i]->committed_tokens.size() + 1;
138	          }
139	          if (total_length > engine_config_->prefill_chunk_size) {
140	            PrefillLaggedTokensByChunk(mstates, running_rsentries, models_[model_id],
141	                                       total_length - engine_config_->prefill_chunk_size);
142	          }
143	        }
144	
145	        for (int i = 0; i < num_rsentries; ++i) {
146	          int num_leaf_nodes = 0;
147	          // Starting from last committed tokens
148	          if (draft_id == 0) {
149	            TVM_FFI_ICHECK_LE(mstates[i]->committed_tokens.size(),
150	                              running_rsentries[i]->mstates[0]->committed_tokens.size());
151	            TVM_FFI_ICHECK_EQ(mstates[i]->num_tokens_for_next_decode, 1);
152	            input_tokens.push_back(mstates[i]->committed_tokens.back().GetTokenId());
153	            input_lengths.push_back(running_rsentries[i]->mstates[0]->committed_tokens.size() -
154	                                    mstates[i]->committed_tokens.size() + 1);
155	            for (size_t j = mstates[i]->committed_tokens.size();
156	                 j < running_rsentries[i]->mstates[0]->committed_tokens.size(); ++j) {
157	              // This draft model is lagging behind the main model.
158	              // It may happen when the engine just switches from the normal batch decode
159	              // mode to the speculative decoding mode.
160	              // In this case, we need to prefill the misaligned tokens into the draft model.
161	              mstates[i]->CommitToken(running_rsentries[i]->mstates[0]->committed_tokens[j]);
162	              input_tokens.push_back(
163	                  running_rsentries[i]->mstates[0]->committed_tokens[j].GetTokenId());
164	            }
165	            mstates[i]->num_tokens_for_next_decode = 0;
166	            draft_token_indices.emplace_back(std::vector<int>{-1});
167	            rngs.push_back(&running_rsentries[i]->rng);
168	            draft_token_parent_idx.push_back(-1);
169	            request_ids_per_leaf_node.push_back(request_ids[i]);
170	            num_leaf_nodes = 1;
171	            cum_num_tokens.push_back(cum_num_tokens.back() + 1);
172	          } else {
173	            TVM_FFI_ICHECK_EQ(mstates[i]->committed_tokens.size(),
174	                              running_rsentries[i]->mstates[0]->committed_tokens.size());
175	            TVM_FFI_ICHECK(!mstates[i]->draft_output_tokens.empty());
176	            draft_token_indices.emplace_back(std::vector<int>{});
177	            // Get all leaf nodes
178	            for (int j = 0; j < static_cast<int>(mstates[i]->draft_output_tokens.size()); ++j) {
179	              if (mstates[i]->draft_token_first_child_idx[j] == -1) {
180	                int64_t parent_idx = mstates[i]->draft_token_parent_idx[j];
181	                token_tree_parent_ptr.push_back(parent_idx);
182	                input_tokens.push_back(mstates[i]->draft_output_tokens[j].GetTokenId());
183	                draft_token_indices.back().push_back(j);
184	                rngs.push_back(&running_rsentries[i]->rng);
185	                num_leaf_nodes++;
186	                request_ids_per_leaf_node.push_back(request_ids[i]);
187	                draft_token_parent_idx.push_back(j);
188	              }
189	            }
190	            input_lengths.push_back(num_leaf_nodes);
191	            cum_num_tokens.push_back(cum_num_tokens.back() + input_lengths.back());
192	          }
193	          GenerationConfig generation_cfg_for_draft = [&]() {
194	            if (engine_config_->spec_tree_width == 1) {
195	              return mstates[i]->request->generation_cfg;
196	            }
197	            auto spec_generation_cfg = tvm::ffi::make_object<GenerationConfigNode>(
198	                *(mstates[i]->request->generation_cfg.get()));
199	            spec_generation_cfg->top_logprobs = engine_config_->spec_tree_width;
200	            spec_generation_cfg->logprobs = true;
201	            spec_generation_cfg->temperature = 1.0;
202	            return GenerationConfig(spec_generation_cfg);
203	          }();
204	          for (int j = 0; j < num_leaf_nodes; ++j) {
205	            generation_cfg.push_back(generation_cfg_for_draft);
206	          }
207	          generation_cfg_for_logitproc.push_back(generation_cfg_for_draft);
208	        }
209	
210	        // - Compute embeddings.
211	        RECORD_EVENT(trace_recorder_, request_ids, "start proposal embedding");
212	        TVM_FFI_ICHECK_LE(input_tokens.size(), engine_config_->prefill_chunk_size);
213	        ObjectRef embeddings =
214	            models_[model_id]->TokenEmbed({Shape{input_tokens.begin(), input_tokens.end()}});
215	        RECORD_EVENT(trace_recorder_, request_ids, "finish proposal embedding");
216	
217	        // - Invoke model decode.
218	        RECORD_EVENT(trace_recorder_, request_ids, "start proposal decode");
219	        Tensor logits{nullptr};
220	
221	        if (input_tokens.size() == num_rsentries) {
222	          // Each request entry only has one token to feed into the draft model.
223	          logits = models_[model_id]->BatchDecode(embeddings, request_internal_ids);
224	          TVM_FFI_ICHECK_EQ(logits->ndim, 3);
225	          TVM_FFI_ICHECK_EQ(logits->shape[0], num_rsentries);
226	          TVM_FFI_ICHECK_EQ(logits->shape[1], 1);
227	        } else if (draft_id == 0) {
228	          // There exists some request entry which has more than one token to feed.
229	          // It may happen when the engine just switches from the normal batch decode
230	          // mode to the speculative decoding mode.
231	          logits = models_[model_id]->BatchPrefill(embeddings, request_internal_ids, input_lengths);
232	          TVM_FFI_ICHECK_EQ(logits->ndim, 3);
233	          TVM_FFI_ICHECK_EQ(logits->shape[0], 1);
234	          TVM_FFI_ICHECK_EQ(logits->shape[1], num_rsentries);
235	        } else {
236	          TVM_FFI_ICHECK_GT(engine_config_->spec_tree_width, 1);
237	          logits = models_[model_id]->BatchTreeDecode(embeddings, request_internal_ids,
238	                                                      input_lengths, token_tree_parent_ptr);
239	          TVM_FFI_ICHECK_EQ(logits->ndim, 3);
240	          TVM_FFI_ICHECK_EQ(logits->shape[0], cum_num_tokens.back());
241	          TVM_FFI_ICHECK_EQ(logits->shape[1], 1);
242	        }
243	        TVM_FFI_ICHECK_EQ(input_lengths.size(), num_rsentries);
244	        RECORD_EVENT(trace_recorder_, request_ids, "finish proposal decode");
245	
246	        // - Update logits.
247	        logits = logits.CreateView({cum_num_tokens.back(), logits->shape[2]}, logits->dtype);
248	
249	        logit_processor_->InplaceUpdateLogits(logits, generation_cfg_for_logitproc, mstates,
250	                                              request_ids, &cum_num_tokens, &mstates,
251	                                              &draft_token_indices);
252	
253	        // - Compute probability distributions.
254	        Tensor probs_on_device = logit_processor_->ComputeProbsFromLogits(
255	            logits, generation_cfg_for_logitproc, request_ids, &cum_num_tokens);
256	
257	        // - Commit the prefix cache changes from previous round of action.
258	        // Note: we commit prefix cache changes here to overlap this commit with the GPU execution.
259	        estate->prefix_cache->CommitSequenceExtention();
260	
261	        // - Sample tokens.
262	        // Fill range [0, num_rsentries) into `sample_indices`.
263	        std::vector<int> sample_indices(cum_num_tokens.back());
264	        std::iota(sample_indices.begin(), sample_indices.end(), 0);
265	        std::vector<Tensor> prob_dist;
266	        Tensor renormalized_probs = sampler_->BatchRenormalizeProbsByTopP(
267	            probs_on_device, sample_indices, request_ids_per_leaf_node, generation_cfg);
268	        std::vector<SampleResult> sample_results = sampler_->BatchSampleTokensWithProbAfterTopP(
269	            renormalized_probs, sample_indices, request_ids_per_leaf_node, generation_cfg, rngs);
270	        TVM_FFI_ICHECK_EQ(sample_results.size(), cum_num_tokens.back());
271	
272	        // - Add draft token to the state.
273	        draft_token_workspace_manager_->AllocSlots(cum_num_tokens.back(), &draft_token_slots_);
274	        models_[model_id]->ScatterDraftProbs(probs_on_device, draft_token_slots_,
275	                                             &model_workspaces_[0].draft_probs_storage);
276	        for (int i = 0; i < num_rsentries; ++i) {
277	          for (int j = cum_num_tokens[i]; j < cum_num_tokens[i + 1]; ++j) {
278	            int parent_idx = draft_token_parent_idx[j];
279	            if (engine_config_->spec_tree_width == 1) {
280	              mstates[i]->AddDraftToken(sample_results[j], draft_token_slots_[j], parent_idx);
281	              continue;
282	            }
283	            for (int k = 0; k < sample_results[j].top_prob_tokens.size(); ++k) {
284	              SampleResult top_k_token{sample_results[j].top_prob_tokens[k]};
285	              mstates[i]->AddDraftToken(top_k_token, draft_token_slots_[j], parent_idx);
286	            }
287	          }
288	        }
289	
290	        auto tdraft_end = std::chrono::high_resolution_clock::now();
291	        estate->metrics.UpdateDraftTimeByBatchSize(
292	            num_rsentries, static_cast<double>((tdraft_end - tdraft_start).count()) / 1e9);
293	      }
294	    }
295	
296	    auto tend = std::chrono::high_resolution_clock::now();
297	    estate->metrics.engine_decode_time_sum += static_cast<double>((tend - tstart).count()) / 1e9;
298	
299	    return {};
300	  }
301	
302	 private:
303	  /*! \brief Check if the input requests can be decoded under conditions. */
304	  bool CanDecode(int num_rsentries) {
305	    // The first model is not involved in draft proposal.
306	    for (int model_id = 1; model_id < static_cast<int>(models_.size()); ++model_id) {
307	      // Check if the model has enough available pages.
308	      int num_available_pages = models_[model_id]->GetNumAvailablePages();
309	      if (num_rsentries > num_available_pages) {
310	        return false;
311	      }
312	    }
313	    return true;
314	  }
315	
316	  void PrefillLaggedTokensByChunk(const Array<RequestModelState>& mstates,
317	                                  const std::vector<RequestStateEntry>& running_rsentries,
318	                                  Model model, int remaining_prefill_length) {
319	    int num_rsentries = mstates.size();
320	    std::vector<int> input_tokens;
321	    std::vector<int64_t> request_internal_ids;
322	    std::vector<int> lengths;
323	    input_tokens.reserve(engine_config_->prefill_chunk_size);
324	    request_internal_ids.reserve(num_rsentries);
325	    lengths.reserve(num_rsentries);
326	
327	    auto f_run_prefill = [&model, &input_tokens, &request_internal_ids, &lengths]() {
328	      ObjectRef embeddings = model->TokenEmbed({Shape{input_tokens.begin(), input_tokens.end()}});
329	      model->BatchPrefill(embeddings, request_internal_ids, lengths);
330	    };
331	
332	    for (int i = 0; i < num_rsentries; ++i) {
333	      int prefill_length =
334	          std::min({static_cast<int>(running_rsentries[i]->mstates[0]->committed_tokens.size() -
335	                                     mstates[i]->committed_tokens.size()),
336	                    static_cast<int>(engine_config_->prefill_chunk_size - input_tokens.size()),
337	                    remaining_prefill_length});
338	      if (prefill_length == 0) {
339	        // This rsentry is done.
340	        continue;
341	      }
342	
343	      TVM_FFI_ICHECK(!mstates[i]->committed_tokens.empty());
344	      for (size_t j = mstates[i]->committed_tokens.size();
345	           j < running_rsentries[i]->mstates[0]->committed_tokens.size(); ++j) {
346	        // Commit the lagging-behind tokens to the draft model.
347	        mstates[i]->CommitToken(running_rsentries[i]->mstates[0]->committed_tokens[j - 1]);
348	        input_tokens.push_back(
349	            running_rsentries[i]->mstates[0]->committed_tokens[j - 1].GetTokenId());
350	      }
351	      lengths.push_back(prefill_length);
352	      request_internal_ids.push_back(running_rsentries[i]->mstates[0]->internal_id);
353	      mstates[i]->num_tokens_for_next_decode = 1;
354	      remaining_prefill_length -= prefill_length;
355	      if (remaining_prefill_length == 0) {
356	        // All rsentries are done.
357	        break;
358	      }
359	
360	      if (input_tokens.size() == engine_config_->prefill_chunk_size) {
361	        // Run prefill if the pending part total length reaches the prefill chunk size.
362	        f_run_prefill();
363	        input_tokens.clear();
364	        request_internal_ids.clear();
365	        lengths.clear();
366	        --i;
367	        continue;
368	      }
369	    }
370	
371	    if (!input_tokens.empty()) {
372	      f_run_prefill();
373	    }
374	  }
375	
376	  /*! \brief The model to run draft generation in speculative decoding. */
377	  Array<Model> models_;
378	  /*! \brief The logit processor. */
379	  LogitProcessor logit_processor_;
380	  /*! \brief The sampler to sample new tokens. */
381	  Sampler sampler_;
382	  /*! \brief The model workspaces. */
383	  std::vector<ModelWorkspace> model_workspaces_;
384	  /*! \brief The draft token workspace manager. */
385	  DraftTokenWorkspaceManager draft_token_workspace_manager_;
386	  /*! \brief The engine config. */
387	  EngineConfig engine_config_;
388	  /*! \brief Event trace recorder. */
389	  Optional<EventTraceRecorder> trace_recorder_;
390	  /*! \brief Temporary buffer to store the slots of the current draft tokens */
391	  std::vector<int> draft_token_slots_;
392	};
393	
394	EngineAction EngineAction::BatchDraft(Array<Model> models, LogitProcessor logit_processor,
395	                                      Sampler sampler, std::vector<ModelWorkspace> model_workspaces,
396	                                      DraftTokenWorkspaceManager draft_token_workspace_manager,
397	                                      EngineConfig engine_config,
398	                                      Optional<EventTraceRecorder> trace_recorder) {
399	  return EngineAction(tvm::ffi::make_object<BatchDraftActionObj>(
400	      std::move(models), std::move(logit_processor), std::move(sampler),
401	      std::move(model_workspaces), std::move(draft_token_workspace_manager),
402	      std::move(engine_config), std::move(trace_recorder)));
403	}
404	
405	}  // namespace serve
406	}  // namespace llm
407	}  // namespace mlc
408

