38	        engine_config_(std::move(engine_config)),
39	        trace_recorder_(std::move(trace_recorder)),
40	        rng_(RandomGenerator::GetInstance()) {}
41	
42	  Array<Request> Step(EngineState estate) final {
43	    // - Only run spec decode when there are two models (llm+ssm) and >=1 running requests.
44	    if (models_.size() != 2 || estate->running_queue.empty()) {
45	      return {};
46	    }
47	
48	    const auto& [rsentries, verify_lengths, total_verify_length] = GetDraftsToVerify(estate);
49	    TVM_FFI_ICHECK_EQ(rsentries.size(), verify_lengths.size());
50	    if (rsentries.empty()) {
51	      return {};
52	    }
53	
54	    auto tstart = std::chrono::high_resolution_clock::now();
55	    int num_rsentries = rsentries.size();
56	    Array<String> request_ids =
57	        rsentries.Map([](const RequestStateEntry& rstate) { return rstate->request->id; });
58	
59	    // - Get embedding and run verify.
60	    std::vector<int64_t> request_internal_ids;
61	    std::vector<int32_t> all_tokens_to_verify;
62	    Array<RequestModelState> verify_request_mstates;
63	    Array<RequestModelState> draft_request_mstates;
64	    Array<GenerationConfig> generation_cfg;
65	    Array<GenerationConfig> generation_cfg_for_top_p_norm;
66	    std::vector<RandomGenerator*> rngs;
67	    std::vector<std::vector<SampleResult>> draft_output_tokens;
68	    std::vector<int64_t> token_tree_parent_ptr;
69	    std::vector<std::vector<int>> draft_token_indices;
70	    token_tree_parent_ptr.reserve(total_verify_length);
71	    request_internal_ids.reserve(num_rsentries);
72	    all_tokens_to_verify.reserve(total_verify_length);
73	    draft_token_indices.reserve(num_rsentries);
74	    verify_request_mstates.reserve(num_rsentries);
75	    draft_request_mstates.reserve(num_rsentries);
76	    rngs.reserve(num_rsentries);
77	    generation_cfg.reserve(num_rsentries);
78	    generation_cfg_for_top_p_norm.reserve(total_verify_length);
79	    draft_output_tokens.reserve(num_rsentries);
80	    draft_token_slots_.clear();
81	    for (int i = 0; i < num_rsentries; ++i) {
82	      RequestModelState verify_mstate = rsentries[i]->mstates[verify_model_id_];
83	      RequestModelState draft_mstate = rsentries[i]->mstates[draft_model_id_];
84	      request_internal_ids.push_back(verify_mstate->internal_id);
85	      TVM_FFI_ICHECK(!verify_lengths.empty());
86	      TVM_FFI_ICHECK_EQ(verify_lengths[i], draft_mstate->draft_output_tokens.size() + 1);
87	      TVM_FFI_ICHECK_EQ(verify_lengths[i], draft_mstate->draft_token_slots.size() + 1);
88	      // the last committed token + all the draft tokens.
89	      draft_token_slots_.push_back(0);  // placeholder for the last committed token
90	      all_tokens_to_verify.push_back(draft_mstate->committed_tokens.back().GetTokenId());
91	      token_tree_parent_ptr.push_back(-1);
92	      generation_cfg_for_top_p_norm.push_back(rsentries[i]->request->generation_cfg);
93	      std::vector<int> cur_draft_token_indices;
94	      cur_draft_token_indices.resize(draft_mstate->draft_output_tokens.size() + 1);
95	      std::iota(cur_draft_token_indices.begin(), cur_draft_token_indices.end(), -1);
96	      for (int j = 0; j < static_cast<int>(draft_mstate->draft_output_tokens.size()); ++j) {
97	        all_tokens_to_verify.push_back(draft_mstate->draft_output_tokens[j].GetTokenId());
98	        draft_token_slots_.push_back(draft_mstate->draft_token_slots[j]);
99	        token_tree_parent_ptr.push_back(draft_mstate->draft_token_parent_idx[j] + 1);
100	        generation_cfg_for_top_p_norm.push_back(rsentries[i]->request->generation_cfg);
101	      }
102	      draft_token_indices.emplace_back(std::move(cur_draft_token_indices));
103	      verify_request_mstates.push_back(verify_mstate);
104	      draft_request_mstates.push_back(draft_mstate);
105	      generation_cfg.push_back(rsentries[i]->request->generation_cfg);
106	      rngs.push_back(&rsentries[i]->rng);
107	      draft_output_tokens.push_back(draft_mstate->draft_output_tokens);
108	    }
109	    Tensor draft_probs_on_device = models_[draft_model_id_]->GatherDraftProbs(
110	        model_workspaces_[verify_model_id_].draft_probs_storage, draft_token_slots_,
111	        &model_workspaces_[verify_model_id_].draft_probs);
112	
113	    RECORD_EVENT(trace_recorder_, request_ids, "start verify embedding");
114	    ObjectRef embeddings = models_[verify_model_id_]->TokenEmbed(
115	        {Shape{all_tokens_to_verify.begin(), all_tokens_to_verify.end()}});
116	    RECORD_EVENT(trace_recorder_, request_ids, "finish verify embedding");
117	
118	    RECORD_EVENT(trace_recorder_, request_ids, "start verify");
119	    Tensor logits = models_[verify_model_id_]->BatchVerify(embeddings, request_internal_ids,
120	                                                           verify_lengths, token_tree_parent_ptr);
121	    RECORD_EVENT(trace_recorder_, request_ids, "finish verify");
122	    TVM_FFI_ICHECK_EQ(logits->ndim, 3);
123	    TVM_FFI_ICHECK_EQ(logits->shape[0], 1);
124	    TVM_FFI_ICHECK_EQ(logits->shape[1], total_verify_length);
125	
126	    // - Update logits.
127	    std::vector<int> cum_verify_lengths = {0};
128	    cum_verify_lengths.reserve(num_rsentries + 1);
129	    for (int i = 0; i < num_rsentries; ++i) {
130	      cum_verify_lengths.push_back(cum_verify_lengths.back() + verify_lengths[i]);
131	    }
132	    logits = logits.CreateView({total_verify_length, logits->shape[2]}, logits->dtype);
133	    logit_processor_->InplaceUpdateLogits(logits, generation_cfg, verify_request_mstates,
134	                                          request_ids, &cum_verify_lengths, &draft_request_mstates,
135	                                          &draft_token_indices);
136	
137	    // - Compute probability distributions.
138	    Tensor probs_on_device = logit_processor_->ComputeProbsFromLogits(
139	        logits, generation_cfg, request_ids, &cum_verify_lengths);
140	
141	    // - Commit the prefix cache changes from previous round of action.
142	    // Note: we commit prefix cache changes here to overlap this commit with the GPU execution.
143	    estate->prefix_cache->CommitSequenceExtention();
144	
145	    // Fill range [0, total_verify_length) into `sample_indices`.
146	    std::vector<int> sample_indices(total_verify_length);
147	    std::iota(sample_indices.begin(), sample_indices.end(), 0);
148	    Tensor renormalized_probs = sampler_->BatchRenormalizeProbsByTopP(
149	        probs_on_device, sample_indices, request_ids, generation_cfg_for_top_p_norm);
150	    auto [sample_results_arr, last_accepted_tree_node_verify_model] =
151	        sampler_->BatchVerifyDraftTokensWithProbAfterTopP(
152	            renormalized_probs, request_ids, cum_verify_lengths, generation_cfg, rngs,
153	            draft_output_tokens, token_tree_parent_ptr, draft_probs_on_device);
154	    TVM_FFI_ICHECK_EQ(sample_results_arr.size(), num_rsentries);
155	
156	    // We collect the requests whose drafts are fully accepted.
157	    // When a request's draft is fully accepted, there is an extra token proposed
158	    // by the draft model but not added into the draft model's KV cache.
159	    // In this case, an additional batch decode step is needed for these requests.
160	    std::vector<int64_t> fully_accepted_rsentries;
161	    std::vector<int64_t> verify_model_seq_internal_ids;
162	    std::vector<int64_t> draft_model_seq_internal_ids;
163	    fully_accepted_rsentries.reserve(num_rsentries);
164	    verify_model_seq_internal_ids.reserve(num_rsentries);
165	    draft_model_seq_internal_ids.reserve(num_rsentries);
166	
167	    // The index of the last accepted tree node in the draft model. This is different from the
168	    // last accepted tree node in the verify model because the first round of draft does not
169	    // use tree attention.
170	    std::vector<int64_t> last_accepted_tree_node_draft_model;
171	    last_accepted_tree_node_draft_model.reserve(num_rsentries);
172	    for (int i = 0; i < num_rsentries; ++i) {
173	      const std::vector<SampleResult>& sample_results = sample_results_arr[i];
174	      int accept_length = sample_results.size();
175	      for (SampleResult sample_result : sample_results) {
176	        rsentries[i]->mstates[verify_model_id_]->CommitToken(sample_result);
177	        rsentries[i]->mstates[draft_model_id_]->CommitToken(sample_result);
178	      }
179	      // Metrics update
180	      // live update the output metrics
181	      rsentries[i]->rstate->metrics.completion_tokens += accept_length;
182	      estate->metrics.spec_decode.Update(cum_verify_lengths[i + 1] - cum_verify_lengths[i],
183	                                         accept_length);
184	      if (engine_config_->spec_tree_width == 1) {
185	        // The roll back is needed for the chain draft case.
186	        int rollback_length =
187	            std::max(cum_verify_lengths[i + 1] - cum_verify_lengths[i] - accept_length, 0);
188	        if (rollback_length > 0) {
189	          // The last accepted token is not yet added into the draft model.
190	          // Therefore, the rollback length for the draft model is one less.
191	          models_[draft_model_id_]->PopNFromKVCache(
192	              rsentries[i]->mstates[draft_model_id_]->internal_id, rollback_length - 1);
193	        }
194	      }
195	      // Commit accepted tokens to the "verify_model", rollback kv cache
196	      // in the "draft_model".
197	      // NOTE: when number of small models is more than 1 (in the future),
198	      // it is possible to re-compute prefill for the small models.
199	      verify_model_seq_internal_ids.push_back(rsentries[i]->mstates[verify_model_id_]->internal_id);
200	      draft_model_seq_internal_ids.push_back(rsentries[i]->mstates[draft_model_id_]->internal_id);
201	      int last_accepted = last_accepted_tree_node_verify_model[i] -
202	                          1;  // minus one to get the index in the draft tokens
203	      if (last_accepted >= 0 &&
204	          rsentries[i]->mstates[draft_model_id_]->draft_token_first_child_idx[last_accepted] ==
205	              -1) {  // minus one to get the index in the draft tokens
206	        // is leaf node, fully accepted
207	        last_accepted_tree_node_draft_model.push_back(
208	            rsentries[i]->mstates[draft_model_id_]->draft_token_parent_idx[last_accepted]);
209	        fully_accepted_rsentries.push_back(i);
210	      } else {
211	        last_accepted_tree_node_draft_model.push_back(last_accepted);
212	      }
213	    }
214	    models_[verify_model_id_]->CommitAcceptedTokenTreeNodesToKVCache(
215	        verify_model_seq_internal_ids,
216	        std::vector<int64_t>{last_accepted_tree_node_verify_model.begin(),
217	                             last_accepted_tree_node_verify_model.end()});
218	    if (engine_config_->spec_tree_width > 1) {
219	      models_[draft_model_id_]->CommitAcceptedTokenTreeNodesToKVCache(
220	          draft_model_seq_internal_ids, last_accepted_tree_node_draft_model);
221	    }
222	
223	    if (!fully_accepted_rsentries.empty()) {
224	      // - Run a step of batch decode for requests whose drafts are fully accepted.
225	      // When a request's draft is fully accepted, there is an extra token proposed
226	      // by the draft model but not added into the draft model's KV cache.
227	      // In this case, an additional batch decode step is needed for these requests.
228	      std::vector<int> input_tokens;
229	      std::vector<int64_t> fully_accepted_request_internal_ids;
230	      input_tokens.reserve(fully_accepted_rsentries.size());
231	      fully_accepted_request_internal_ids.reserve(fully_accepted_rsentries.size());
232	      for (int rsentry_id : fully_accepted_rsentries) {
233	        int num_committed_tokens =
234	            rsentries[rsentry_id]->mstates[verify_model_id_]->committed_tokens.size();
235	        // When a request's draft is fully accepted, an additional new token is sampled.
236	        // So the token needed to fill in the draft model is the committed_token[-2].
237	        TVM_FFI_ICHECK_GE(num_committed_tokens, 2);
238	        input_tokens.push_back(rsentries[rsentry_id]
239	                                   ->mstates[verify_model_id_]
240	                                   ->committed_tokens[num_committed_tokens - 2]
241	                                   .GetTokenId());
242	        fully_accepted_request_internal_ids.push_back(
243	            rsentries[rsentry_id]->mstates[draft_model_id_]->internal_id);
244	      }
245	      // - Compute embeddings.
246	      ObjectRef embeddings =
247	          models_[draft_model_id_]->TokenEmbed({Shape{input_tokens.begin(), input_tokens.end()}});
248	      // - Invoke model decode.
249	      Tensor logits =
250	          models_[draft_model_id_]->BatchDecode(embeddings, fully_accepted_request_internal_ids);
251	      // - We explicitly synchronize to avoid the input tokens getting overriden in the
252	      // next runs of BatchDecode.
253	      // This is because we do not do sample for this round of batch decode.
254	      DeviceAPI::Get(logits->device)->StreamSync(logits->device, nullptr);
255	    }
256	
257	    // clear the draft model state entries
258	    for (int i = 0; i < num_rsentries; ++i) {
259	      rsentries[i]->mstates[draft_model_id_]->RemoveAllDraftTokens(&draft_token_slots_);
260	      draft_token_workspace_manager_->FreeSlots(draft_token_slots_);
261	      // reset num_tokens_for_next_decode to 1
262	      rsentries[i]->mstates[verify_model_id_]->num_tokens_for_next_decode = 1;
263	      rsentries[i]->mstates[draft_model_id_]->num_tokens_for_next_decode = 1;
264	    }
265	
266	    auto tend = std::chrono::high_resolution_clock::now();
267	    double elapsed_time = static_cast<double>((tend - tstart).count()) / 1e9;
268	    estate->metrics.engine_decode_time_sum += elapsed_time;
269	    estate->metrics.UpdateVerifyTimeByBatchSize(total_verify_length, elapsed_time);
270	
271	    return estate->running_queue;
272	  }
273	
274	 private:
275	  struct DraftRequestStateEntries {
276	    /*! \brief The request state entries to verify. */
277	    Array<RequestStateEntry> draft_rsentries;
278	    /*! \brief The length to verify for each request state. */
279	    std::vector<int> verify_lengths;
280	    /*! \brief The total draft length. */
281	    int total_verify_length;
282	  };
283	
284	  /*!
285	   * \brief Decide whether to run verify for the draft of each request.
286	   * \param estate The engine state.
287	   * \return The drafts to verify, together with their respective
288	   * state and input length.
289	   */
290	  DraftRequestStateEntries GetDraftsToVerify(EngineState estate) {
291	    std::vector<int> verify_lengths;
292	    int total_verify_length = 0;
293	    int total_required_pages = 0;
294	    int num_available_pages = models_[verify_model_id_]->GetNumAvailablePages();
295	
296	    // Preempt the request state entries that cannot fit the large model for verification.
297	    std::vector<RequestStateEntry> init_running_rsentries = estate->GetRunningRequestStateEntries();
298	    std::vector<int> num_page_requirement;
299	    num_page_requirement.reserve(init_running_rsentries.size());
300	    std::vector<RequestStateEntry> running_rsentries;
301	    running_rsentries.reserve(init_running_rsentries.size());
302	    for (const RequestStateEntry& rsentry : init_running_rsentries) {
303	      int draft_length = rsentry->mstates[draft_model_id_]->draft_output_tokens.size();
304	      if (draft_length == 0) {
305	        continue;
306	      }
307	      running_rsentries.push_back(rsentry);
308	      int num_require_pages = (draft_length + engine_config_->kv_cache_page_size - 1) /
309	                              engine_config_->kv_cache_page_size;
310	      verify_lengths.push_back(draft_length + 1);
311	      num_page_requirement.push_back(num_require_pages);
312	      total_verify_length += draft_length + 1;
313	      total_required_pages += num_require_pages;
314	    }
315	    while (!CanVerify(total_required_pages)) {
316	      if (estate->prefix_cache->TryFreeMemory()) continue;
317	      RequestStateEntry preempted = PreemptLastRunningRequestStateEntry(
318	          estate, models_, draft_token_workspace_manager_, trace_recorder_);
319	      if (preempted.same_as(running_rsentries.back())) {
320	        total_verify_length -= verify_lengths.back();
321	        total_required_pages -= num_page_requirement.back();
322	        verify_lengths.pop_back();
323	        num_page_requirement.pop_back();
324	        running_rsentries.pop_back();
325	      }
326	    }
327	    TVM_FFI_ICHECK_LE(total_verify_length,
328	                      std::min(static_cast<int64_t>(engine_config_->max_num_sequence),
329	                               engine_config_->prefill_chunk_size))
330	        << total_verify_length << " " << engine_config_->max_num_sequence;
331	
332	    return {running_rsentries, verify_lengths, total_verify_length};
333	  }
334	
335	  bool CanVerify(int num_required_pages) {
336	    int num_available_pages = models_[0]->GetNumAvailablePages();
337	    return num_required_pages <= num_available_pages;
338	  }
339	
340	  /*!
341	   * \brief The model to run decode in. When there are multiple
342	   * models, the `Step` function of the created action will not take effect.
343	   */
344	  Array<Model> models_;
345	  /*! \brief The logit processor. */
346	  LogitProcessor logit_processor_;
347	  /*! \brief The sampler to sample new tokens. */
348	  Sampler sampler_;
349	  /*! \brief The model workspaces. */
350	  std::vector<ModelWorkspace> model_workspaces_;
351	  /*! \brief The draft token workspace manager. */
352	  DraftTokenWorkspaceManager draft_token_workspace_manager_;
353	  /*! \brief The engine config. */
354	  EngineConfig engine_config_;
355	  /*! \brief Event trace recorder. */
356	  Optional<EventTraceRecorder> trace_recorder_;
357	  /*! \brief Random number generator. */
358	  RandomGenerator& rng_;
359	  /*! \brief The ids of verify/draft models. */
360	  const int verify_model_id_ = 0;
361	  const int draft_model_id_ = 1;
362	  const float eps_ = 1e-5;
363	  /*! \brief Temporary buffer to store the slots of the current draft tokens */
364	  std::vector<int> draft_token_slots_;
365	};
366	
367	EngineAction EngineAction::BatchVerify(Array<Model> models, LogitProcessor logit_processor,
368	                                       Sampler sampler,
369	                                       std::vector<ModelWorkspace> model_workspaces,
370	                                       DraftTokenWorkspaceManager draft_token_workspace_manager,
371	                                       EngineConfig engine_config,
372	                                       Optional<EventTraceRecorder> trace_recorder) {
373	  return EngineAction(tvm::ffi::make_object<BatchVerifyActionObj>(
374	      std::move(models), std::move(logit_processor), std::move(sampler),
375	      std::move(model_workspaces), std::move(draft_token_workspace_manager),
376	      std::move(engine_config), std::move(trace_recorder)));
377	}
378	
379	}  // namespace serve
380	}  // namespace llm
381	}  // namespace mlc
