1	/*!
2	 *  Copyright (c) 2023-2025 by Contributors
3	 * \file serve/engine_actions/eagle_batch_verify.cc
4	 */
5	
6	#include <cmath>
7	#include <exception>
8	#include <numeric>
9	
10	#include "../../support/random.h"
11	#include "../config.h"
12	#include "../model.h"
13	#include "../sampler/sampler.h"
14	#include "action.h"
15	#include "action_commons.h"
16	
17	namespace mlc {
18	namespace llm {
19	namespace serve {
20	
21	/*!
22	 * \brief The action that runs verification for requests in the
23	 * `running_queue` of engine state. Preempt low-priority requests
24	 * accordingly when it is impossible to decode all the running requests.
25	 */
26	class EagleBatchVerifyActionObj : public EngineActionObj {
27	 public:
28	  explicit EagleBatchVerifyActionObj(Array<Model> models, LogitProcessor logit_processor,
29	                                     Sampler sampler, std::vector<ModelWorkspace> model_workspaces,
30	                                     DraftTokenWorkspaceManager draft_token_workspace_manager,
31	                                     EngineConfig engine_config,
32	                                     Optional<EventTraceRecorder> trace_recorder)
33	      : models_(std::move(models)),
34	        logit_processor_(std::move(logit_processor)),
35	        sampler_(std::move(sampler)),
36	        model_workspaces_(std::move(model_workspaces)),
37	        draft_token_workspace_manager_(std::move(draft_token_workspace_manager)),
38	        engine_config_(std::move(engine_config)),
39	        trace_recorder_(std::move(trace_recorder)),
40	        rng_(RandomGenerator::GetInstance()) {}
41	
42	  Array<Request> Step(EngineState estate) final {
43	    // - Only run spec decode when there are two models (llm+ssm) and >=1 running requests.
44	    if (models_.size() != 2 || estate->running_queue.empty()) {
45	      return {};
46	    }
47	
48	    const auto& [rsentries, draft_lengths, total_draft_length] = GetDraftsToVerify(estate);
49	    TVM_FFI_ICHECK_EQ(rsentries.size(), draft_lengths.size());
50	    if (rsentries.empty()) {
51	      return {};
52	    }
53	
54	    auto tstart = std::chrono::high_resolution_clock::now();
55	    int num_rsentries = rsentries.size();
56	    Array<String> request_ids =
57	        rsentries.Map([](const RequestStateEntry& rstate) { return rstate->request->id; });
58	
59	    // - Get embedding and run verify.
60	    std::vector<int64_t> request_internal_ids;
61	    std::vector<int32_t> all_tokens_to_verify;
62	    Array<RequestModelState> verify_request_mstates;
63	    Array<RequestModelState> draft_request_mstates;
64	    Array<GenerationConfig> generation_cfg;
65	    std::vector<RandomGenerator*> rngs;
66	    std::vector<std::vector<SampleResult>> draft_output_tokens;
67	    std::vector<std::vector<int>> draft_token_indices;
68	    std::vector<int64_t> token_tree_parent_ptr;
69	    request_internal_ids.reserve(num_rsentries);
70	    all_tokens_to_verify.reserve(total_draft_length);
71	    token_tree_parent_ptr.reserve(total_draft_length);
72	    verify_request_mstates.reserve(num_rsentries);
73	    draft_request_mstates.reserve(num_rsentries);
74	    rngs.reserve(num_rsentries);
75	    generation_cfg.reserve(num_rsentries);
76	    draft_output_tokens.reserve(num_rsentries);
77	    draft_token_indices.reserve(num_rsentries);
78	    draft_token_slots_.clear();
79	
80	    for (int i = 0; i < num_rsentries; ++i) {
81	      RequestModelState verify_mstate = rsentries[i]->mstates[verify_model_id_];
82	      RequestModelState draft_mstate = rsentries[i]->mstates[draft_model_id_];
83	      request_internal_ids.push_back(verify_mstate->internal_id);
84	      TVM_FFI_ICHECK(!draft_lengths.empty());
85	      TVM_FFI_ICHECK_EQ(draft_lengths[i], draft_mstate->draft_output_tokens.size());
86	      TVM_FFI_ICHECK_EQ(draft_lengths[i], draft_mstate->draft_token_slots.size());
87	      // the last committed token + all the draft tokens but the last one.
88	      all_tokens_to_verify.push_back(draft_mstate->committed_tokens.back().GetTokenId());
89	      draft_token_slots_.push_back(0);  // placeholder for the last committed token
90	      token_tree_parent_ptr.push_back(-1);
91	
92	      for (int j = 0; j < static_cast<int>(draft_mstate->draft_output_tokens.size()); ++j) {
93	        all_tokens_to_verify.push_back(draft_mstate->draft_output_tokens[j].GetTokenId());
94	        draft_token_slots_.push_back(draft_mstate->draft_token_slots[j]);
95	        token_tree_parent_ptr.push_back(draft_mstate->draft_token_parent_idx[j] + 1);
96	      }
97	      std::vector<int> cur_draft_token_indices(draft_mstate->draft_output_tokens.size() + 1);
98	      std::iota(cur_draft_token_indices.begin(), cur_draft_token_indices.end(), -1);
99	      draft_token_indices.emplace_back(std::move(cur_draft_token_indices));
100	      verify_request_mstates.push_back(verify_mstate);
101	      draft_request_mstates.push_back(draft_mstate);
102	      generation_cfg.push_back(rsentries[i]->request->generation_cfg);
103	      rngs.push_back(&rsentries[i]->rng);
104	      draft_output_tokens.push_back(draft_mstate->draft_output_tokens);
105	    }
106	
107	    Tensor draft_probs_on_device = models_[draft_model_id_]->GatherDraftProbs(
108	        model_workspaces_[verify_model_id_].draft_probs_storage, draft_token_slots_,
109	        &model_workspaces_[verify_model_id_].draft_probs);
110	
111	    std::vector<int> cum_verify_lengths = {0};
112	    cum_verify_lengths.reserve(num_rsentries + 1);
113	    std::vector<int> verify_lengths;
114	    for (int i = 0; i < num_rsentries; ++i) {
115	      // Add one committed token.
116	      verify_lengths.push_back(draft_lengths[i] + 1);
117	      cum_verify_lengths.push_back(cum_verify_lengths.back() + verify_lengths.back());
118	    }
119	
120	    RECORD_EVENT(trace_recorder_, request_ids, "start verify embedding");
121	    ObjectRef embeddings = models_[verify_model_id_]->TokenEmbed(
122	        {Shape{all_tokens_to_verify.begin(), all_tokens_to_verify.end()}});
123	    RECORD_EVENT(trace_recorder_, request_ids, "finish verify embedding");
124	
125	    RECORD_EVENT(trace_recorder_, request_ids, "start verify");
126	    ObjectRef hidden_states = models_[verify_model_id_]->BatchVerifyToLastHidden(
127	        embeddings, request_internal_ids, verify_lengths, token_tree_parent_ptr);
128	    Tensor logits = models_[verify_model_id_]->GetLogits(hidden_states);
129	    RECORD_EVENT(trace_recorder_, request_ids, "finish verify");
130	    TVM_FFI_ICHECK_EQ(logits->ndim, 2);
131	    TVM_FFI_ICHECK_EQ(logits->shape[0], cum_verify_lengths.back());
132	
133	    // - Update logits.
134	    logit_processor_->InplaceUpdateLogits(logits, generation_cfg, verify_request_mstates,
135	                                          request_ids, &cum_verify_lengths, &draft_request_mstates,
136	                                          &draft_token_indices);
137	
138	    // - Compute probability distributions.
139	    Tensor probs_on_device = logit_processor_->ComputeProbsFromLogits(
140	        logits, generation_cfg, request_ids, &cum_verify_lengths);
141	
142	    // - Commit the prefix cache changes from previous round of action.
143	    // Note: we commit prefix cache changes here to overlap this commit with the GPU execution.
144	    estate->prefix_cache->CommitSequenceExtention();
145	
146	    std::vector<int> sample_indices(num_rsentries);
147	    std::iota(sample_indices.begin(), sample_indices.end(), 0);
148	    Tensor renormalized_probs = sampler_->BatchRenormalizeProbsByTopP(
149	        probs_on_device, sample_indices, request_ids, generation_cfg);
150	    auto [sample_results_arr, _] = sampler_->BatchVerifyDraftTokensWithProbAfterTopP(
151	        renormalized_probs, request_ids, cum_verify_lengths, generation_cfg, rngs,
152	        draft_output_tokens, token_tree_parent_ptr, draft_probs_on_device);
153	    TVM_FFI_ICHECK_EQ(sample_results_arr.size(), num_rsentries);
154	
155	    // We collect the requests whose drafts are fully accepted.
156	    // When a request's draft is fully accepted, there is an extra token proposed
157	    // by the draft model but not added into the draft model's KV cache.
158	    // In this case, an additional batch decode step is needed for these requests.
159	    std::vector<int64_t> fully_accepted_rsentries;
160	    std::vector<int64_t> verify_model_seq_internal_ids;
161	    std::vector<int64_t> accepted_token_tree_leaf_nodes;
162	    fully_accepted_rsentries.reserve(num_rsentries);
163	    verify_model_seq_internal_ids.reserve(num_rsentries);
164	    accepted_token_tree_leaf_nodes.reserve(num_rsentries);
165	
166	    std::vector<int> last_accepted_hidden_positions;
167	    last_accepted_hidden_positions.reserve(num_rsentries);
168	    for (int i = 0; i < num_rsentries; ++i) {
169	      const std::vector<SampleResult>& sample_results = sample_results_arr[i];
170	      int accept_length = sample_results.size();
171	      TVM_FFI_ICHECK_GE(accept_length, 1);
172	      for (SampleResult sample_result : sample_results) {
173	        rsentries[i]->mstates[verify_model_id_]->CommitToken(sample_result);
174	        rsentries[i]->mstates[draft_model_id_]->CommitToken(sample_result);
175	      }
176	      // Metrics update
177	      // live update the output metrics
178	      rsentries[i]->rstate->metrics.completion_tokens += accept_length;
179	      rsentries[i]->rstate->metrics.decode_tokens += accept_length;
180	      estate->metrics.spec_decode.Update(cum_verify_lengths[i + 1] - cum_verify_lengths[i],
181	                                         accept_length);
182	      // - Minus one because the last draft token has no kv cache entry
183	      // - Take max with 0 in case of all accepted.
184	      int rollback_length =
185	          std::max(cum_verify_lengths[i + 1] - cum_verify_lengths[i] - accept_length, 0);
186	
187	      // Commit accepted tokens to the "verify_model", rollback kv cache
188	      // in the "draft_model".
189	      // NOTE: when number of small models is more than 1 (in the future),
190	      // it is possible to re-compute prefill for the small models.
191	      verify_model_seq_internal_ids.push_back(rsentries[i]->mstates[verify_model_id_]->internal_id);
192	      accepted_token_tree_leaf_nodes.push_back(accept_length - 1);
193	      if (rollback_length > 0) {
194	        // Draft model rollback minus one because verify uses one more token.
195	        models_[draft_model_id_]->PopNFromKVCache(
196	            rsentries[i]->mstates[draft_model_id_]->internal_id, rollback_length - 1);
197	      } else {
198	        fully_accepted_rsentries.push_back(i);
199	      }
200	      // clear the draft model state entries
201	      rsentries[i]->mstates[draft_model_id_]->RemoveAllDraftTokens(&draft_token_slots_);
202	      draft_token_workspace_manager_->FreeSlots(draft_token_slots_);
203	      // - Slice and save hidden_states_for_sample
204	      last_accepted_hidden_positions.push_back(cum_verify_lengths[i] + accept_length - 1);
205	    }
206	    models_[verify_model_id_]->CommitAcceptedTokenTreeNodesToKVCache(
207	        verify_model_seq_internal_ids, accepted_token_tree_leaf_nodes);
208	    if (!fully_accepted_rsentries.empty() &&
209	        engine_config_->speculative_mode == SpeculativeMode::kEagle) {
210	      // - Run a step of batch decode for requests whose drafts are fully accepted.
211	      // When a request's draft is fully accepted, there is an extra token proposed
212	      // by the draft model but not added into the draft model's KV cache.
213	      // In this case, an additional batch decode step is needed for these requests.
214	      std::vector<int> input_tokens;
215	      std::vector<int64_t> fully_accepted_request_internal_ids;
216	      input_tokens.reserve(fully_accepted_rsentries.size());
217	      fully_accepted_request_internal_ids.reserve(fully_accepted_rsentries.size());
218	
219	      std::vector<int> hidden_states_positions_for_fully_accepted;
220	      hidden_states_positions_for_fully_accepted.reserve(fully_accepted_rsentries.size());
221	
222	      for (int rsentry_id : fully_accepted_rsentries) {
223	        int num_committed_tokens =
224	            rsentries[rsentry_id]->mstates[verify_model_id_]->committed_tokens.size();
225	        // When a request's draft is fully accepted, an additional new token is sampled.
226	        // So the token needed to fill in the draft model is the committed_token[-2].
227	        TVM_FFI_ICHECK_GE(num_committed_tokens, 2);
228	        input_tokens.push_back(rsentries[rsentry_id]
229	                                   ->mstates[verify_model_id_]
230	                                   ->committed_tokens[num_committed_tokens - 2]
231	                                   .GetTokenId());
232	
233	        // Taking the hidden states of the token before the last token
234	        hidden_states_positions_for_fully_accepted.push_back(
235	            last_accepted_hidden_positions[rsentry_id] - 1);
236	        fully_accepted_request_internal_ids.push_back(
237	            rsentries[rsentry_id]->mstates[draft_model_id_]->internal_id);
238	      }
239	
240	      // - Compute embeddings.
241	      ObjectRef embeddings =
242	          models_[draft_model_id_]->TokenEmbed({Shape{input_tokens.begin(), input_tokens.end()}});
243	      // - Gather hidden states
244	      ObjectRef hidden_states_for_fully_accepted = models_[draft_model_id_]->GatherHiddenStates(
245	          hidden_states, hidden_states_positions_for_fully_accepted,
246	          &model_workspaces_[draft_model_id_].hidden_states);
247	      // - Invoke model decode.
248	      ObjectRef fused_embedding_hidden_states = models_[draft_model_id_]->FuseEmbedHidden(
249	          embeddings, hidden_states_for_fully_accepted,
250	          /*batch_size*/ fully_accepted_rsentries.size(), /*seq_len*/ 1);
251	      hidden_states_for_fully_accepted = models_[draft_model_id_]->BatchDecodeToLastHidden(
252	          fused_embedding_hidden_states, fully_accepted_request_internal_ids);
253	      // - We explicitly synchronize to avoid the input tokens getting overriden in the
254	      // next runs of BatchDecode.
255	      // This is because we do not do sample for this round of batch decode.
256	      if (hidden_states_for_fully_accepted->IsInstance<DRefObj>()) {
257	        (hidden_states_for_fully_accepted.as_or_throw<DRef>()->session)
258	            .as_or_throw<Session>()
259	            ->SyncWorker(0);
260	      } else {
261	        Tensor hidden_states_for_fully_accepted_nd =
262	            hidden_states_for_fully_accepted.as_or_throw<Tensor>();
263	        DeviceAPI::Get(hidden_states_for_fully_accepted_nd->device)
264	            ->StreamSync(hidden_states_for_fully_accepted_nd->device, nullptr);
265	      }
266	    }
267	    {
268	      // One step draft for the following steps
269	
270	      // Gather hidden states for the last accepted tokens.
271	      // Use the function and the workspace of the verify model because the information about the
272	      // hidden states is not available in the draft model for medusa.
273	      hidden_states = models_[0]->GatherHiddenStates(hidden_states, last_accepted_hidden_positions,
274	                                                     &model_workspaces_[0].hidden_states);
275	
276	      std::vector<int> input_tokens;
277	      Array<RequestModelState> mstates;
278	      input_tokens.reserve(num_rsentries);
279	      mstates.reserve(num_rsentries);
280	      for (const RequestStateEntry& rsentry : rsentries) {
281	        mstates.push_back(rsentry->mstates[draft_model_id_]);
282	      }
283	      for (int i = 0; i < num_rsentries; ++i) {
284	        TVM_FFI_ICHECK(!mstates[i]->committed_tokens.empty());
285	        input_tokens.push_back(mstates[i]->committed_tokens.back().GetTokenId());
286	      }
287	
288	      Array<Tensor> multi_step_logits{nullptr};  // for medusa output
289	      if (engine_config_->speculative_mode == SpeculativeMode::kEagle) {
290	        // - Compute embeddings.
291	        RECORD_EVENT(trace_recorder_, request_ids, "start proposal embedding");
292	        embeddings =
293	            models_[draft_model_id_]->TokenEmbed({Shape{input_tokens.begin(), input_tokens.end()}});
294	        RECORD_EVENT(trace_recorder_, request_ids, "finish proposal embedding");
295	
296	        // - Invoke model decode.
297	        RECORD_EVENT(trace_recorder_, request_ids, "start proposal decode");
298	        ObjectRef fused_embedding_hidden_states = models_[draft_model_id_]->FuseEmbedHidden(
299	            embeddings, hidden_states, /*batch_size*/ num_rsentries, /*seq_len*/ 1);
300	        hidden_states = models_[draft_model_id_]->BatchDecodeToLastHidden(
301	            fused_embedding_hidden_states, request_internal_ids);
302	
303	        int lm_head_model_id = models_[draft_model_id_]->CanGetLogits() ? draft_model_id_ : 0;
304	        logits = models_[lm_head_model_id]->GetLogits(hidden_states);
305	        RECORD_EVENT(trace_recorder_, request_ids, "finish proposal decode");
306	        TVM_FFI_ICHECK_EQ(logits->ndim, 2);
307	        TVM_FFI_ICHECK_EQ(logits->shape[0], num_rsentries);
308	      } else if (engine_config_->speculative_mode == SpeculativeMode::kMedusa) {
309	        multi_step_logits = models_[draft_model_id_]->GetMultiStepLogits(hidden_states);
310	      }
311	
312	      // Fill range [0, num_rsentries) into `sample_indices`.
313	      std::vector<int> sample_indices(num_rsentries);
314	      std::iota(sample_indices.begin(), sample_indices.end(), 0);
315	
316	      if (engine_config_->speculative_mode == SpeculativeMode::kEagle) {
317	        const auto& [renormalized_probs, sample_results] = ApplyLogitProcessorAndSample(
318	            logit_processor_, sampler_, logits, generation_cfg, request_ids, mstates, rngs,
319	            sample_indices, generation_cfg, request_ids, sample_indices);
320	        UpdateRequestStatesWithDraftProposals(mstates, sample_results, draft_model_id_,
321	                                              renormalized_probs, hidden_states, estate);
322	      } else if (engine_config_->speculative_mode == SpeculativeMode::kMedusa) {
323	        TVM_FFI_ICHECK_NE(estate->spec_draft_length, 0);
324	        for (int draft_id = 0; draft_id < estate->spec_draft_length; draft_id++) {
325	          const auto& [renormalized_probs, sample_results] = ApplyLogitProcessorAndSample(
326	              logit_processor_, sampler_, multi_step_logits[draft_id], generation_cfg, request_ids,
327	              mstates, rngs, sample_indices, generation_cfg, request_ids, sample_indices);
328	          UpdateRequestStatesWithDraftProposals(mstates, sample_results, draft_model_id_,
329	                                                renormalized_probs, hidden_states, estate);
330	        }
331	      }
332	    }
333	    // reset num_tokens_for_next_decode
334	    for (const RequestStateEntry& rsentry : rsentries) {
335	      rsentry->mstates[verify_model_id_]->num_tokens_for_next_decode = 0;
336	      rsentry->mstates[draft_model_id_]->num_tokens_for_next_decode = 0;
337	    }
338	    auto tend = std::chrono::high_resolution_clock::now();
339	    double elapsed_time = static_cast<double>((tend - tstart).count()) / 1e9;
340	    estate->metrics.engine_decode_time_sum += elapsed_time;
341	    estate->metrics.UpdateVerifyTimeByBatchSize(cum_verify_lengths.back(), elapsed_time);
342	
343	    return estate->running_queue;
344	  }
345	
346	 private:
347	  struct DraftRequestStateEntries {
348	    /*! \brief The request state entries to verify. */
349	    Array<RequestStateEntry> draft_rsentries;
350	    /*! \brief The draft length of each request state. */
351	    std::vector<int> draft_lengths;
352	    /*! \brief The total draft length. */
353	    int total_draft_length;
354	  };
355	
356	  /*!
357	   * \brief Decide whether to run verify for the draft of each request.
358	   * \param estate The engine state.
359	   * \return The drafts to verify, together with their respective
360	   * state and input length.
361	   */
362	  DraftRequestStateEntries GetDraftsToVerify(EngineState estate) {
363	    std::vector<int> draft_lengths;
364	    int total_draft_length = 0;
365	    int total_required_pages = 0;
366	    int num_available_pages = models_[verify_model_id_]->GetNumAvailablePages();
367	
368	    // Preempt the request state entries that cannot fit the large model for verification.
369	    std::vector<RequestStateEntry> running_rsentries = estate->GetRunningRequestStateEntries();
370	    std::vector<int> num_page_requirement;
371	    num_page_requirement.reserve(running_rsentries.size());
372	    for (const RequestStateEntry& rsentry : running_rsentries) {
373	      int draft_length = rsentry->mstates[draft_model_id_]->draft_output_tokens.size();
374	      int num_require_pages = (draft_length + engine_config_->kv_cache_page_size - 1) /
375	                              engine_config_->kv_cache_page_size;
376	      draft_lengths.push_back(draft_length);
377	      num_page_requirement.push_back(num_require_pages);
378	      total_draft_length += draft_length;
379	      total_required_pages += num_require_pages;
380	    }
381	    while (!CanVerify(total_required_pages)) {
382	      if (estate->prefix_cache->TryFreeMemory()) continue;
383	      RequestStateEntry preempted = PreemptLastRunningRequestStateEntry(
384	          estate, models_, draft_token_workspace_manager_, trace_recorder_);
385	      if (preempted.same_as(running_rsentries.back())) {
386	        total_draft_length -= draft_lengths.back();
387	        total_required_pages -= num_page_requirement.back();
388	        draft_lengths.pop_back();
389	        num_page_requirement.pop_back();
390	        running_rsentries.pop_back();
391	      }
392	    }
393	
394	    return {running_rsentries, draft_lengths, total_draft_length};
395	  }
396	
397	  bool CanVerify(int num_required_pages) {
398	    int num_available_pages = models_[0]->GetNumAvailablePages();
399	    return num_required_pages <= num_available_pages;
400	  }
401	
402	  void UpdateRequestStatesWithDraftProposals(const Array<RequestModelState>& mstates,
403	                                             const std::vector<SampleResult>& sample_results,
404	                                             int model_id, const Tensor& renormalized_probs,
405	                                             const ObjectRef& hidden_states_for_sample,
406	                                             EngineState estate) {
407	    draft_token_workspace_manager_->AllocSlots(mstates.size(), &draft_token_slots_);
408	    models_[0]->ScatterDraftProbs(renormalized_probs, draft_token_slots_,
409	                                  &model_workspaces_[0].draft_probs_storage);
410	    if (engine_config_->speculative_mode == SpeculativeMode::kEagle &&
411	        estate->spec_draft_length > 1) {
412	      models_[0]->ScatterHiddenStates(hidden_states_for_sample, draft_token_slots_,
413	                                      &model_workspaces_[0].draft_hidden_states_storage);
414	    }
415	    for (int i = 0; i < static_cast<int>(mstates.size()); ++i) {
416	      int64_t parent_idx = static_cast<int64_t>(mstates[i]->draft_output_tokens.size()) - 1;
417	      mstates[i]->AddDraftToken(sample_results[i], draft_token_slots_[i], parent_idx);
418	    }
419	  }
420	  /*!
421	   * \brief The model to run decode in. When there are multiple
422	   * models, the `Step` function of the created action will not take effect.
423	   */
424	  Array<Model> models_;
425	  /*! \brief The logit processor. */
426	  LogitProcessor logit_processor_;
427	  /*! \brief The sampler to sample new tokens. */
428	  Sampler sampler_;
429	  /*! \brief Workspace of each model. */
430	  std::vector<ModelWorkspace> model_workspaces_;
431	  /*! \brief The draft token workspace manager. */
432	  DraftTokenWorkspaceManager draft_token_workspace_manager_;
433	  /*! \brief The engine config. */
434	  EngineConfig engine_config_;
435	  /*! \brief Event trace recorder. */
436	  Optional<EventTraceRecorder> trace_recorder_;
437	  /*! \brief Random number generator. */
438	  RandomGenerator& rng_;
439	  /*! \brief The ids of verify/draft models. */
440	  const int verify_model_id_ = 0;
441	  const int draft_model_id_ = 1;
442	  const float eps_ = 1e-5;
443	  /*! \brief Temporary buffer to store the slots of the current draft tokens */
444	  std::vector<int> draft_token_slots_;
445	};
446	
447	EngineAction EngineAction::EagleBatchVerify(
448	    Array<Model> models, LogitProcessor logit_processor, Sampler sampler,
449	    std::vector<ModelWorkspace> model_workspaces,
450	    DraftTokenWorkspaceManager draft_token_workspace_manager, EngineConfig engine_config,
451	    Optional<EventTraceRecorder> trace_recorder) {
452	  return EngineAction(tvm::ffi::make_object<EagleBatchVerifyActionObj>(
453	      std::move(models), std::move(logit_processor), std::move(sampler),
454	      std::move(model_workspaces), std::move(draft_token_workspace_manager),
455	      std::move(engine_config), std::move(trace_recorder)));
456	}
457	
458	}  // namespace serve
459	}  // namespace llm
460	}  // namespace mlc
