139	void RemoveRequestFromModel(EngineState estate, int64_t req_internal_id,
140	                            const Array<Model>& models) {
141	  // Remove the request from all models (usually the KV cache).
142	  for (Model model : models) {
143	    model->RemoveSequence(req_internal_id);
144	  }
