147	/*!
148	 * \brief Remove the given request state entry.
149	 * \param estate The engine state to update after removal.
150	 * \param models The models to remove the given request from.
151	 * \param rsentry The request state entry to remove.
152	 */
153	void RemoveRequestStateEntry(EngineState estate, const Array<Model>& models,
154	                             RequestStateEntry rsentry,
155	                             Optional<DraftTokenWorkspaceManager> draft_token_workspace_manager) {
156	  if (draft_token_workspace_manager.has_value()) {
157	    std::vector<int> draft_token_slots;
158	    for (const RequestModelState& mstate : rsentry->mstates) {
159	      mstate->RemoveAllDraftTokens(&draft_token_slots);
160	      draft_token_workspace_manager.value()->FreeSlots(draft_token_slots);
161	    }
162	  }
163	  if (estate->prefix_cache->HasSequence(rsentry->mstates[0]->internal_id)) {
164	    // If the sequence is stored in prefix cache, call prefix cache to remove.
165	    if (!(rsentry->request->generation_cfg->debug_config.pinned_system_prompt)) {
166	      // If the request is not pinned, recycle the request.
167	      estate->prefix_cache->RecycleSequence(rsentry->mstates[0]->internal_id, /*lazy=*/true);
168	    }
169	    // If the request is pinned, do nothing over the prefix cache and KVCache.
170	  } else {
171	    // If the sequence is not stored in prefix cache, remove it directly.
172	    RemoveRequestFromModel(estate, rsentry->mstates[0]->internal_id, models);
173	    estate->id_manager.RecycleId(rsentry->mstates[0]->internal_id);
174	  }
175	}
