177	void ProcessFinishedRequestStateEntries(
178	    const std::vector<RequestStateEntry>& finished_rsentries, EngineState estate,
179	    const Array<Model>& models, int max_single_sequence_length,
180	    Optional<DraftTokenWorkspaceManager> draft_token_workspace_manager,
181	    Array<RequestStreamOutput>* callback_delta_outputs) {
182	  NVTXScopedRange nvtx_scope("Process finished requests");
183	  // - Remove the finished request state entries.
184	  for (const RequestStateEntry& rsentry : finished_rsentries) {
185	    // The finished entry must be a leaf.
186	    TVM_FFI_ICHECK(rsentry->child_indices.empty());
187	    // Mark the status of this entry as finished.
188	    rsentry->status = RequestStateStatus::kFinished;
189	    // Remove the request state entry from all the models.
190	    RemoveRequestStateEntry(estate, models, rsentry, draft_token_workspace_manager);
191	
192	    RequestState rstate = estate->GetRequestState(rsentry->request);
193	    int parent_idx = rsentry->parent_idx;
194	    while (parent_idx != -1) {
195	      bool all_children_finished = true;
196	      for (int child_idx : rstate->entries[parent_idx]->child_indices) {
197	        if (rstate->entries[child_idx]->status != RequestStateStatus::kFinished) {
198	          all_children_finished = false;
199	          break;
200	        }
201	      }
202	      if (!all_children_finished) {
203	        break;
204	      }
205	
206	      // All the children of the parent request state entry have finished.
207	      // So we mark the parent entry as finished.
208	      rstate->entries[parent_idx]->status = RequestStateStatus::kFinished;
209	      // Remove the request state entry from all the models.
210	
211	      RemoveRequestStateEntry(estate, models, rstate->entries[parent_idx],
212	                              draft_token_workspace_manager);
213	      // Climb up to the parent.
214	      parent_idx = rstate->entries[parent_idx]->parent_idx;
215	    }
216	
217	    if (parent_idx == -1) {
218	      // Remove from running queue and engine state.
219	      auto it =
220	          std::find(estate->running_queue.begin(), estate->running_queue.end(), rsentry->request);
221	      TVM_FFI_ICHECK(it != estate->running_queue.end());
222	      estate->running_queue.erase(it);
223	      estate->request_states.erase(rsentry->request->id);
224	
225	      // Update engine metrics.
226	      const RequestStateEntry& root_rsentry = rstate->entries[0];
227	      auto trequest_finish = std::chrono::high_resolution_clock::now();
228	
229	      rstate->metrics.finish_time_point = trequest_finish;
230	      estate->metrics.RequestFinishUpdate(rstate->metrics);
231	
232	      // always stream back usage in backend
233	      callback_delta_outputs->push_back(RequestStreamOutput::Usage(
234	          root_rsentry->request->id, rstate->metrics.AsUsageJSONStr(true)));
235	    }
236	    estate->running_rsentries_changed = true;
237	  }
238	}
