240	void ActionStepPostProcess(Array<Request> requests, EngineState estate, const Array<Model>& models,
241	                           const Tokenizer& tokenizer,
242	                           FRequestStreamCallback request_stream_callback,
243	                           int64_t max_single_sequence_length,
244	                           Optional<DraftTokenWorkspaceManager> draft_token_workspace_manager,
245	                           Optional<EventTraceRecorder> trace_recorder) {
246	  NVTXScopedRange nvtx_scope("EngineAction postproc");
247	  int num_requests = requests.size();
248	  estate->postproc_workspace.finished_rsentries.clear();
249	  estate->postproc_workspace.callback_delta_outputs.clear();
250	  estate->postproc_workspace.finished_rsentries.reserve(num_requests);
251	  estate->postproc_workspace.callback_delta_outputs.reserve(num_requests * 2);
252	
253	  // - Collect new generated tokens and finish reasons for requests.
254	  for (int r = 0; r < num_requests; ++r) {
255	    Request request = requests[r];
256	    int n = request->generation_cfg->n;
257	    RequestState rstate = estate->GetRequestState(requests[r]);
258	
259	    bool invoke_callback = false;
260	    RequestStreamOutput stream_output = rstate->postproc_states.GetStreamOutput();
261	    for (int i = 0; i < n; ++i) {
262	      const RequestStateEntry& rsentry = n == 1 ? rstate->entries[0] : rstate->entries[i + 1];
263	      rsentry->GetDeltaRequestReturn(tokenizer, max_single_sequence_length, &stream_output, i);
264	      if (stream_output->group_finish_reason[i].has_value()) {
265	        invoke_callback = true;
266	        estate->postproc_workspace.finished_rsentries.push_back(rsentry);
267	      }
268	      if (!stream_output->group_delta_token_ids[i].empty() ||
269	          !stream_output->group_extra_prefix_string[i].empty()) {
270	        invoke_callback = true;
271	      }
272	    }
273	
274	    if (invoke_callback) {
275	      stream_output->unpacked = false;
276	      estate->postproc_workspace.callback_delta_outputs.push_back(std::move(stream_output));
277	    }
278	
279	    // Update prefix cache and metrics.
280	    for (const RequestStateEntry& rsentry : rstate->entries) {
281	      std::vector<int32_t>& token_ids = rsentry->token_ids_for_prefix_cache_update;
282	      token_ids.clear();
283	      if (!rsentry->mstates[0]->prefilled_inputs.empty()) {
284	        // Notify the prefix cache of the newly prefilled data.
285	        for (const Data& data : rsentry->mstates[0]->prefilled_inputs) {
286	          const TokenDataNode* token_data = data.as<TokenDataNode>();
287	          if (token_data == nullptr) continue;
288	          token_ids.insert(token_ids.end(), token_data->token_ids->data,
289	                           token_data->token_ids->data + token_data->token_ids.size());
290	          // note that we are counting prefill tokens across all branches
291	          rstate->metrics.prefill_tokens += data->GetLength();
292	        }
293	        rsentry->mstates[0]->prefilled_inputs.clear();
294	      }
295	      int64_t num_committed_tokens = rsentry->mstates[0]->committed_tokens.size();
296	      if (rsentry->mstates[0]->cached_committed_tokens < num_committed_tokens - 1) {
297	        // Notify the prefix cache of the newly decoded data, except the last token as it is not
298	        // in KVCache yet.
299	        for (int64_t& i = rsentry->mstates[0]->cached_committed_tokens;
300	             i < num_committed_tokens - 1; ++i) {
301	          token_ids.push_back(rsentry->mstates[0]->committed_tokens[i].sampled_token_id.first);
302	        }
303	      }
304	      if (!token_ids.empty()) {
305	        estate->prefix_cache->ExtendSequence(rsentry->mstates[0]->internal_id, token_ids);
306	      }
307	    }
308	
309	    // - For all disaggregation requests with "remote_send",
310	    // if it does not appear in the waiting queue, it means the prefill has been finished.
311	    // In this case, we mark the request as finished.
312	    if (request->generation_cfg->debug_config.disagg_config.kind ==
313	        DisaggRequestKind::kRemoteSend) {
314	      auto it = std::find(estate->waiting_queue.begin(), estate->waiting_queue.end(), request);
315	      if (it == estate->waiting_queue.end()) {
316	        TVM_FFI_ICHECK_EQ(rstate->entries.size(), 1);
317	        estate->postproc_workspace.finished_rsentries.push_back(rstate->entries[0]);
318	      }
319	    }
320	  }
321	
322	  ProcessFinishedRequestStateEntries(estate->postproc_workspace.finished_rsentries, estate, models,
323	                                     max_single_sequence_length, draft_token_workspace_manager,
324	                                     &estate->postproc_workspace.callback_delta_outputs);
325	
326	  if (!estate->postproc_workspace.callback_delta_outputs.empty()) {
327	    NVTXScopedRange nvtx_scope("Call request stream callback");
328	    // - Invoke the stream callback function once for all collected requests.
329	    request_stream_callback(estate->postproc_workspace.callback_delta_outputs);
330	  }
331	}  // namespace serve
332	
333	RequestStateEntry PreemptLastRunningRequestStateEntry(
334	    EngineState estate, const Array<Model>& models,
335	    Optional<DraftTokenWorkspaceManager> draft_token_workspace_manager,
336	    Optional<EventTraceRecorder> trace_recorder) {
337	  TVM_FFI_ICHECK(!estate->running_queue.empty());
338	  Request request = estate->running_queue.back();
339	
340	  // Find the last alive request state entry, which is what we want to preempt.
341	  RequestState rstate = estate->GetRequestState(request);
342	  int preempt_rstate_idx = -1;
343	  for (int i = static_cast<int>(rstate->entries.size()) - 1; i >= 0; --i) {
344	    if (rstate->entries[i]->status == RequestStateStatus::kAlive) {
345	      preempt_rstate_idx = i;
346	      break;
347	    }
348	  }
349	  TVM_FFI_ICHECK_NE(preempt_rstate_idx, -1);
350	  RequestStateEntry rsentry = rstate->entries[preempt_rstate_idx];
351	  if (estate->disaggregation) {
352	    AbortRequestImpl(estate, models, request->id, "preempt");
353	    return rsentry;
354	  }
355	  // When the request state entry still has pending inputs,
356	  // it means the request is still in the waiting queue.
357	  bool partially_alive = !rsentry->mstates[0]->inputs.empty();
358	
359	  // Remove from models.
360	  // - Clear model speculation draft.
361	  // - Update `inputs` for future prefill.
362	  RECORD_EVENT(trace_recorder, rsentry->request->id, "preempt");
363	  rsentry->status = RequestStateStatus::kPending;
364	  std::vector<int> draft_token_slots;
365	  for (RequestModelState mstate : rsentry->mstates) {
366	    if (draft_token_workspace_manager.has_value()) {
367	      mstate->RemoveAllDraftTokens(&draft_token_slots);
368	      draft_token_workspace_manager.value()->FreeSlots(draft_token_slots);
369	    }
370	
371	    // If the commited tokens of the current model lags behind the
372	    // committed tokens of the main model (models[0]), we commit those
373	    // new tokens to this model.
374	    for (size_t i = mstate->committed_tokens.size();
375	         i < rsentry->mstates[0]->committed_tokens.size(); ++i) {
376	      mstate->CommitToken(rsentry->mstates[0]->committed_tokens[i]);
377	    }
378	
379	    std::vector<int32_t> committed_token_ids;
380	    committed_token_ids.reserve(mstate->committed_tokens.size());
381	    for (const SampleResult& committed_token : mstate->committed_tokens) {
382	      committed_token_ids.push_back(committed_token.GetTokenId());
383	    }
384	    mstate->num_prefilled_tokens = 0;
385	
386	    Array<Data> inputs;
387	    if (rsentry->parent_idx == -1) {
388	      inputs = request->inputs;
389	      if (const auto* token_input = inputs.back().as<TokenDataNode>()) {
390	        // Merge the TokenData so that a single time TokenEmbed is needed.
391	        std::vector<int> token_ids{token_input->token_ids->data,
392	                                   token_input->token_ids->data + token_input->token_ids.size()};
393	        token_ids.insert(token_ids.end(), committed_token_ids.begin(), committed_token_ids.end());
394	        inputs.Set(static_cast<int64_t>(inputs.size()) - 1, TokenData(token_ids));
395	      } else if (!committed_token_ids.empty()) {
396	        inputs.push_back(TokenData(committed_token_ids));
397	      }
398	    } else if (!committed_token_ids.empty()) {
399	      inputs.push_back(TokenData(committed_token_ids));
400	    }
401	    mstate->inputs = std::move(inputs);
402	    mstate->prefilled_inputs.clear();
403	    mstate->cached_committed_tokens = 0;
404	    mstate->num_tokens_for_next_decode = 0;
405	  }
406	  if (estate->prefix_cache->HasSequence(rsentry->mstates[0]->internal_id)) {
407	    estate->prefix_cache->RecycleSequence(rsentry->mstates[0]->internal_id, /*lazy=*/false);
408	  } else {
409	    RemoveRequestFromModel(estate, rsentry->mstates[0]->internal_id, models);
410	  }
411	  // Since the sequence has been removed from model, assign a new sequence ID.
412	  int64_t new_seq_id = estate->id_manager.GetNewId();
413	  for (RequestModelState mstate : rsentry->mstates) {
414	    mstate->internal_id = new_seq_id;
415	  }
416	
417	  if (preempt_rstate_idx == 0) {
418	    // Remove from running queue.
419	    estate->running_queue.erase(estate->running_queue.end() - 1);
420	  }
421	  if (!partially_alive && preempt_rstate_idx == static_cast<int>(rstate->entries.size()) - 1) {
422	    // Add to the front of waiting queue.
423	    estate->waiting_queue.insert(estate->waiting_queue.begin(), request);
424	  }
425	  estate->running_rsentries_changed = true;
426	  return rsentry;
427	}
428	
429	std::pair<Tensor, std::vector<SampleResult>> ApplyLogitProcessorAndSample(
430	    const LogitProcessor& logit_processor, const Sampler& sampler, const Tensor& logits,
431	    const Array<GenerationConfig>& generation_cfg, const Array<String>& request_ids,
432	    const Array<RequestModelState>& mstates, const std::vector<RandomGenerator*>& rngs,
433	    const std::vector<int>& sample_indices, const Array<GenerationConfig>& child_generation_cfg,
434	    const Array<String>& child_request_ids, const std::vector<int>& child_sample_indices) {
435	  // - Update logits.
436	  logit_processor->InplaceUpdateLogits(logits, generation_cfg, mstates, request_ids);
437	
438	  // - Compute probability distributions.
439	  Tensor probs_on_device =
440	      logit_processor->ComputeProbsFromLogits(logits, generation_cfg, request_ids);
441	
442	  // - Sample tokens.
443	  Tensor renormalized_probs = sampler->BatchRenormalizeProbsByTopP(probs_on_device, sample_indices,
444	                                                                   request_ids, generation_cfg);
445	  std::vector<SampleResult> sample_results = sampler->BatchSampleTokensWithProbAfterTopP(
446	      renormalized_probs, child_sample_indices, child_request_ids, child_generation_cfg, rngs);
447	  return {std::move(probs_on_device), std::move(sample_results)};
448	}
449	
450	}  // namespace serve
451	}  // namespace llm
452	}  // namespace mlc
